solutions.python:
class Solution:
  def fix_media_queries(self, css: str) -> str: queries = css.split('@media'); queries.sort(key=lambda q: max(f.strip().split(':')[0] for f in q.split(' and '))); return '@media' + ''.join(queries[1:])


var css = 'body { width: 100px; }
@media (max-width: 800px) and (orientation: landscape) { width: 200px; }
@media (max-width: 600px) and (orientation: portrait) { width: 300px; }
@media (max-width: 400px) and (orientation: landscape) { width: 400px; }';

var result = fixMediaQueries(css);
console.log(result);

